"use client";
import { useEffect, useRef } from "react";

const pillars = [
  {
    index: "01",
    title: "Systems Thinker",
    // EDIT THIS LATER — rewrite in your own voice, specific to your experience
    desc: "I design from data model to deploy. Architecture decisions, API contracts, and scaling tradeoffs are where I thrive.",
  },
  {
    index: "02",
    title: "Business-Aware",
    // EDIT THIS LATER — describe your actual business understanding
    desc: "I understand retention loops, unit economics, and why shipping fast often beats shipping perfect.",
  },
  {
    index: "03",
    title: "Full-Stack Builder",
    // EDIT THIS LATER — specify the layers you own: frontend/backend/infra/etc.
    desc: "From DB schema to UI component — I own the full product. No handoff friction, no translation loss.",
  },
];

export default function ValueProp() {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { el.classList.add("visible"); obs.disconnect(); } },
      { threshold: 0.1 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="section" id="about">
      <div className="wrap">
        <div className="section-label">What I bring</div>
        <div ref={ref} className="fade-up pillars">
          {pillars.map((p) => (
            <div key={p.index} className="pillar">
              <span className="pillar-index">{p.index}</span>
              <div className="pillar-title">{p.title}</div>
              <p className="pillar-desc">{p.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
